// File: tcp_vs_udp_demo.dart
// Run: dart tcp_vs_udp_demo.dart
import 'dart:io';
import 'dart:typed_data';
import 'dart:async';

void main() async {
  // ─────────────── TCP ───────────────
  final tcpServer = await ServerSocket.bind('127.0.0.1', 0);
  print('TCP server listening on port ${tcpServer.port}');
  tcpServer.listen((sock) async {
    sock.write('You said: ' + String.fromCharCodes(await sock.first));
    await sock.close();
  });

  final t0 = DateTime.now();
  final client = await Socket.connect('127.0.0.1', tcpServer.port);
  client.write('hello');
  await client.close();
  final reply = String.fromCharCodes(await client.fold<List<int>>([], (a,b)=>a..addAll(b)));
  final tcpMs = DateTime.now().difference(t0).inMilliseconds;
  print('TCP: took $tcpMs ms; reply: "$reply"');
  print('  (that time includes SYN, SYN-ACK, ACK, data, FIN/ACK...)');

  // ─────────────── UDP ───────────────
  final udpServer = await RawDatagramSocket.bind('127.0.0.1', 0);
  print('\nUDP server listening on port ${udpServer.port}');
  udpServer.listen((_) {
    final dg = udpServer.receive();
    if (dg != null) {
      print('UDP server got: "${String.fromCharCodes(dg.data)}" from ${dg.address}:${dg.port}');
    }
  });

  final u = await RawDatagramSocket.bind('127.0.0.1', 0);
  final t1 = DateTime.now();
  u.send(Uint8List.fromList('hello'.codeUnits), InternetAddress('127.0.0.1'), udpServer.port);
  final udpMs = DateTime.now().difference(t1).inMilliseconds;
  print('UDP send returned in $udpMs ms');
  print('  (no handshake, no ACK — we don\'t even know if it arrived)');

  await Future.delayed(Duration(milliseconds: 100));
  udpServer.close(); u.close(); tcpServer.close();
}

// Typical output:
// TCP server listening on port 54321
// TCP: took 3 ms; reply: "You said: hello"
//   (that time includes SYN, SYN-ACK, ACK, data, FIN/ACK...)
// UDP server listening on port 54322
// UDP send returned in 0 ms
//   (no handshake, no ACK — we don't even know if it arrived)
// UDP server got: "hello" from 127.0.0.1:54323
